@startuml
!theme plain
skinparam backgroundColor #FFFFFF
skinparam packageStyle rectangle
skinparam packageBackgroundColor #F5F5F5
skinparam packageBorderColor #000000
skinparam packageFontColor #000000

package "main" {
  class "main" {
    <<actor>>
    "main" as main
  }

  class "getInput" {
    <<class>>
    "getInput" as getInput
  }

  class "sortList" {
    <<class>>
    "sortList" as sortList
  }

  class "writeOutput" {
    <<class>>
    "writeOutput" as writeOutput
  }

  main --> getInput
  getInput --> sortList
  sortList --> writeOutput
}

@enduml
